const { spawn } = require("child_process");

const worker = spawn("npm", ["run", "worker"], {
  stdio: "inherit",
  shell: process.platform === "win32",
});

const startClient = () =>
  new Promise((resolve) => {
    const client = spawn("npm", ["run", "client"], {
      stdio: "inherit",
      shell: process.platform === "win32",
    });

    client.on("exit", (code) => {
      resolve(code ?? 0);
    });
  });

const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

(async () => {
  try {
    await delay(2000);
    const code = await startClient();
    worker.kill();
    process.exit(code);
  } catch (error) {
    worker.kill();
    console.error(error);
    process.exit(1);
  }
})();

export async function squareNumber(n: number): Promise<number> {
  return n * n;
}

import { proxyActivities } from "@temporalio/workflow";
import type * as activities from "./activities";

const { squareNumber } = proxyActivities<typeof activities>({
  startToCloseTimeout: "1 minute",
});

export async function ParallelSquaresWorkflow(numbers: number[]): Promise<number> {
  const activityPromises = numbers.map((value) => squareNumber(value));
  const results = await Promise.all(activityPromises);
  return results.reduce((sum, value) => sum + value, 0);
}

import { NativeConnection, Worker } from "@temporalio/worker";
import { squareNumber } from "./activities";

const taskQueue = "parallel-squares-ts";

const {
  TEMPORAL_API_KEY: apiKey,
  TEMPORAL_ADDRESS: address,
  TEMPORAL_NAMESPACE: namespace,
} = process.env;

if (!apiKey || !address || !namespace) {
  throw new Error(
    "Missing TEMPORAL_API_KEY, TEMPORAL_ADDRESS, or TEMPORAL_NAMESPACE environment variables."
  );
}

async function run(): Promise<void> {
  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue,
    workflowsPath: require.resolve("./workflows"),
    activities: { squareNumber },
  });

  await worker.run();
}

run().catch((error) => {
  console.error(error);
  process.exit(1);
});

import { Client, Connection } from "@temporalio/client";
import { ParallelSquaresWorkflow } from "./workflows";

const taskQueue = "parallel-squares-ts";

const {
  TEMPORAL_API_KEY: apiKey,
  TEMPORAL_ADDRESS: address,
  TEMPORAL_NAMESPACE: namespace,
  ZEALT_RUN_ID: runId,
} = process.env;

if (!apiKey || !address || !namespace || !runId) {
  throw new Error(
    "Missing TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE, or ZEALT_RUN_ID environment variables."
  );
}

async function run(): Promise<void> {
  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const numbers = [1, 2, 3, 4, 5];

  const result = await client.workflow.execute(ParallelSquaresWorkflow, {
    taskQueue,
    workflowId: `parallel-wf-${runId}`,
    args: [numbers],
  });

  console.log(result);
}

run().catch((error) => {
  console.error(error);
  process.exit(1);
});
